function Releases() {
  return (
    <div className="pt-32 pb-20 bg-gray-900 min-h-screen">
      <div className="max-w-7xl mx-auto px-6">
        <h1 className="text-5xl font-bold mb-12 text-center">Upcoming Releases</h1>
        <p className="text-xl text-center mb-12 text-gray-300">
          Most anticipated movies coming to theaters in 2026 – mark your calendars! (As of January 2026)
        </p>

        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-10">
          {upcomingMovies.map((movie) => (
            <div 
              key={movie.id} 
              className="bg-gray-800 rounded-xl overflow-hidden shadow-xl hover:shadow-2xl transition-all duration-300 hover:scale-[1.03]"
            >
              <img 
                src={movie.poster} 
                alt={movie.title} 
                className="w-full h-80 object-cover" 
              />
              <div className="p-6">
                <h2 className="text-2xl font-bold mb-2">{movie.title}</h2>
                <p className="text-rose-400 font-semibold mb-3">{movie.releaseDate}</p>
                <p className="text-gray-300 mb-2"><strong>Cast:</strong> {movie.cast}</p>
                <p className="text-gray-300 mb-2"><strong>Director:</strong> {movie.director}</p>
                <div className="flex flex-wrap gap-2 mb-4">
                  <span className="bg-rose-900/50 px-3 py-1 rounded-full text-sm">{movie.genre}</span>
                </div>
                <p className="text-gray-300 mb-6 line-clamp-3">{movie.description}</p>
                <button 
                  className="w-full bg-rose-600 hover:bg-rose-700 text-white font-semibold py-3 rounded-lg transition-colors"
                  onClick={() => alert(`Notify me for ${movie.title} – coming soon!`)} // Placeholder for future notify
                >
                  Get Notified / Watch Trailer
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default Releases;